func TestEnumBatchResponseStatus(t *testing.T) {
	t.Run("NewFromString_SUCCESS", func(t *testing.T) {
		t.Parallel()
		val, err := NewBatchResponseStatusFromString("SUCCESS")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, BatchResponseStatus("SUCCESS"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_PARTIAL_FAILURE", func(t *testing.T) {
		t.Parallel()
		val, err := NewBatchResponseStatusFromString("PARTIAL_FAILURE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, BatchResponseStatus("PARTIAL_FAILURE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_FAILURE", func(t *testing.T) {
		t.Parallel()
		val, err := NewBatchResponseStatusFromString("FAILURE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, BatchResponseStatus("FAILURE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewBatchResponseStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewBatchResponseStatusFromString("SUCCESS")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

